import SwiftUI
import WeatherKit
import CoreLocation

private let kCacheInterval: TimeInterval = 30 * 60
private let kNewYork = CLLocation(latitude: 40.7128, longitude: -74.0060)

@MainActor
class WeatherViewModel: ObservableObject {
    @Published var currentWeather: CurrentWeather?
    @Published var isLoading = false
    @Published var errorMessage: String?

    private var cachedWeather: Weather?
    private var lastFetchTime: Date?

    func fetchWeather() {
        if let cached = cachedWeather, let time = lastFetchTime, Date().timeIntervalSince(time) < kCacheInterval {
            currentWeather = cached.currentWeather
            isLoading = false
            errorMessage = nil
            return
        }
        isLoading = true
        errorMessage = nil
        Task {
            do {
                let weather = try await WeatherService.shared.weather(for: kNewYork, including: .current)
                cachedWeather = weather
                lastFetchTime = Date()
                currentWeather = weather.currentWeather
                isLoading = false
                errorMessage = nil
            } catch {
                isLoading = false
                errorMessage = error.localizedDescription
            }
        }
    }
}

struct WeatherView: View {
    @StateObject private var viewModel = WeatherViewModel()

    var body: some View {
        Group {
            if viewModel.isLoading {
                ProgressView("Loading…")
            } else if let message = viewModel.errorMessage {
                Text(message)
                    .foregroundStyle(.red)
            } else if let current = viewModel.currentWeather {
                VStack(spacing: 8) {
                    if let temp = current.temperature {
                        Text("\(Int(temp.value))°")
                            .font(.largeTitle)
                    }
                    if let condition = current.condition {
                        Text(String(describing: condition))
                            .font(.subheadline)
                    }
                }
            }
        }
        .onAppear { viewModel.fetchWeather() }
    }
}
